struct VowelInfo {
    char vowel;
    int count;
    int first_occurrence;
};

bool compareVowels(const VowelInfo& a, const VowelInfo& b) {
    // Primary criterion: Frequency descending
    if (a.count != b.count) {
        return a.count > b.count;
    }
    // Secondary criterion: First appearance ascending
    return a.first_occurrence < b.first_occurrence;
}

std::string solve(std::string s) {
    std::map<char, int> vowelCounts;
    std::map<char, int> firstOccurrence;
    std::vector<int> vowelPositions;

    // 1. Analyze the string: count, track first occurrences, and record positions
    for (int i = 0; i < s.length(); ++i) {
        char c = s[i];
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            vowelPositions.push_back(i);

            // Count
            vowelCounts[c]++;

            // First occurrence
            if (firstOccurrence.find(c) == firstOccurrence.end()) {
                firstOccurrence[c] = i;
            }
        }
    }

    // 2. Prepare and sort vowel information
    std::vector<VowelInfo> uniqueVowelsInfo;
    for (const auto& pair : vowelCounts) {
        char vowel = pair.first;
        int count = pair.second;
        int first_idx = firstOccurrence[vowel];
        uniqueVowelsInfo.push_back({vowel, count, first_idx});
    }

    // Sort using the custom comparator
    std::sort(uniqueVowelsInfo.begin(), uniqueVowelsInfo.end(), compareVowels);

    // 3. Construct the replacement sequence of all vowels
    std::string replacementVowels = "";
    for (const auto& info : uniqueVowelsInfo) {
        char vowel = info.vowel;
        int count = info.count;
        for (int i = 0; i < count; ++i) {
            replacementVowels += vowel;
        }
    }

    // 4. Reconstruct the string
    std::string result = s;

    // Place the sorted vowels back into the original vowel positions
    for (size_t i = 0; i < vowelPositions.size(); ++i) {
        int position = vowelPositions[i];
        char replacementChar = replacementVowels[i];
        result[position] = replacementChar;
    }

    return result;
}

