function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);

    const vowelCounts = {};
    const firstOccurrence = {};
    const vowelPositions = [];

    // 1 & 2: Analysis pass
    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            vowelPositions.push(i);

            // Count
            vowelCounts[char] = (vowelCounts[char] || 0) + 1;

            // First occurrence
            if (!(char in firstOccurrence)) {
                firstOccurrence[char] = i;
            }
        }
    }

    // Get unique vowels present
    const uniqueVowels = Object.keys(vowelCounts);

    // 3: Sorting unique vowels
    // Sort criteria: 
    // 1. Frequency (descending)
    // 2. First Appearance Index (ascending)
    uniqueVowels.sort((v1, v2) => {
        const count1 = vowelCounts[v1];
        const count2 = vowelCounts[v2];

        // Primary: Frequency descending
        if (count1 !== count2) {
            return count2 - count1; // If count2 > count1, return positive, v2 comes first
        }

        // Secondary: First appearance ascending
        const first1 = firstOccurrence[v1];
        const first2 = firstOccurrence[v2];
        return first1 - first2; // If first1 < first2, return negative, v1 comes first
    });

    // 4: Construct Replacement Sequence
    const replacementVowels = [];
    for (const vowel of uniqueVowels) {
        const count = vowelCounts[vowel];
        for (let i = 0; i < count; i++) {
            replacementVowels.push(vowel);
        }
    }

    // 5: Reconstruction
    // Start with a mutable array representation of the string
    const sArr = Array.from(s);

    // Replace vowels at stored positions using the sorted sequence
    for (let i = 0; i < vowelPositions.length; i++) {
        const position = vowelPositions[i];
        const replacementChar = replacementVowels[i];
        sArr[position] = replacementChar;
    }

    return sArr.join('');
}
```

